policies.inbound:




        {{McpClientId}}
        api://{{McpClientId}}



<set-variable name="mcpTokenAccessType" value="@{
    var authHeader = context.Request.Headers.GetValueOrDefault("Authorization", string.Empty);
    if (string.IsNullOrEmpty(authHeader))
    {
        return "missing";
    }

    var token = authHeader.StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase)
        ? authHeader.Substring(7)
        : authHeader;
    var segments = token.Split('.');
    if (segments.Length < 2)
    {
        return "invalid";
    }

    var payload = segments[1].Replace('-', '+').Replace('_', '/');
    switch (payload.Length % 4)
    {
        case 2:
            payload += "==";
            break;
        case 3:
            payload += "=";
            break;
    }

    var claimsJson = Encoding.UTF8.GetString(Convert.FromBase64String(payload));
    var claims = JObject.Parse(claimsJson);

    var delegatedScopes = ((string)claims["scp"] ?? string.Empty)
        .Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
    if (delegatedScopes.Any(scope => string.Equals(scope, "user_impersonation", StringComparison.Ordinal)))
    {
        return "delegated";
    }

    var rolesClaim = claims["roles"];
    if (rolesClaim != null)
    {
        if (rolesClaim.Type == JTokenType.Array && rolesClaim.Any(role => string.Equals((string)role, "access_as_application", StringComparison.Ordinal)))
        {
            return "application";
        }

        if (rolesClaim.Type != JTokenType.Array && string.Equals((string)rolesClaim, "access_as_application", StringComparison.Ordinal))
        {
            return "application";
        }
    }

    return "insufficient";
}" />






                Bearer error="insufficient_scope", resource_metadata="{{APIMGatewayURL}}/.well-known/oauth-protected-resource"

            Access token must contain delegated scope 'user_impersonation' or application role 'access_as_application'.





    {{function-host-key}}



    application/json, text/event-stream
